    )';
  ELSE
    EXECUTE 'CREATE TABLE IF NOT EXISTS course_tee_header (
      id BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
      course_id BIGINT REFERENCES course_header(id) ON DELETE CASCADE,
      name TEXT NOT NULL,
      color TEXT NOT NULL
    )';
  END IF;

  -- Check if we already have data to avoid duplicates
  SELECT count(*) INTO tee_count FROM course_tee_header;

  IF tee_count = 0 THEN
    -- Insert sample tees for existing courses
    INSERT INTO course_tee_header (course_id, name, color)
