    INSERT INTO course_tee_header (course_id, name, color)
    SELECT id, 'Forward (Red)', '#FF0000' FROM course_header;

    INSERT INTO course_tee_header (course_id, name, color)
    SELECT id, 'Pro (Blue)', '#0000FF' FROM course_header;
  END IF;
END $$;

ALTER TABLE course_tee_header ENABLE ROW LEVEL SECURITY;
DROP POLICY IF EXISTS "Enable read access for all users" ON course_tee_header;
